---- MODULE ATM ----
EXTENDS Integers, Sequences, FiniteSets

VARIABLES state, card, pin, amount, dispensed

Init == /\ state = "Idle"
        /\ card = {}
        /\ pin = {}
        /\ amount = 0
        /\ dispensed = {}

Next == \/ /\ state = "Idle"
          /\ card' = {}
          /\ pin' = {}
          /\ amount' = 0
          /\ dispensed' = {}
          /\ state' = "CardInserted"
        \/ /\ state = "CardInserted"
          /\ card' = card
          /\ pin' = {}
          /\ amount' = 0
          /\ dispensed' = {}
          /\ state' = "PINEntered"
        \/ /\ state = "PINEntered"
          /\ card' = card
          /\ pin' = pin
          /\ amount' = 0
          /\ dispensed' = {}
          /\ state' = "Dispensing"
        \/ /\ state = "Dispensing"
          /\ card' = card
          /\ pin' = pin
          /\ amount' = amount
          /\ dispensed' = {}
          /\ state' = "Done"
        \/ /\ state = "Done"
          /\ card' = {}
          /\ pin' = {}
          /\ amount' = 0
          /\ dispensed' = {}
          /\ state' = "Idle"

Spec == Init /\ [][Next]_<<state, card, pin, amount, dispensed>>

