---- MODULE Door ----
EXTENDS Integers, Sequences, FiniteSets

VARIABLES doorState, doorLock

DoorState == {"Open", "Closed", "Locked"}
DoorLock == {"Unlocked", "Locked"}

Init == /\ doorState \in DoorState
       /\ doorLock \in DoorLock
       /\ doorState \in {"Closed", "Locked"}
       /\ doorLock \in {"Unlocked", "Locked"}

Next == \/ /\ doorState' = "Open"
          /\ doorState \in {"Closed", "Locked"}
          /\ doorLock' = doorLock
       \/ /\ doorState' = "Closed"
          /\ doorState \in {"Open", "Locked"}
          /\ doorLock' = doorLock
       \/ /\ doorState' = "Locked"
          /\ doorState \in {"Closed"}
          /\ doorLock' = "Locked"

Spec == Init /\ [][Next]_<<doorState, doorLock>>

