          /\ dispensed' = {}
          /\ state' = "CardInserted"
        \/ /\ state = "CardInserted"
          /\ card' = card
          /\ pin' = {}
          /\ dispensed' = {}
          /\ state' = "PINEntered"
        \/ /\ state = "PINEntered"
          /\ card' = card
          /\ pin' = pin
          /\ dispensed' = {}
          /\ state' = "Dispensing"
        \/ /\ state = "Dispensing"
          /\ card' = card
          /\ pin' = pin
          /\ dispensed' = {}
          /\ state' = "Done"
        \/ /\ state = "Done"
          /\ card' = {}
          /\ pin' = {}
          /\ dispensed' = {}
          /\ state' = "Idle"

(* --specification-- *)
Spec == Init /\ [][Next]_<<state, card, pin, dispensed>>

